test_cases.python_test_script:
def test_tc_hz_001(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    assert all(get_bdy_hazard_active(m.data) == 0 for m in msgs)

def test_tc_hz_002(can_bus):
    msgs = collect_bcm_messages(can_bus, 2.0)
    assert all(get_bdy_hazard_active(m.data) == 1 for m in msgs)

def test_tc_hz_003(can_bus):
    vals = [get_bdy_hazard_active(m.data) for m in collect_bcm_messages(can_bus, 2.0)]
    assert 0 in vals and 1 in vals
